package Entites;import java.time.LocalDate;public class MedicalRecords {    private String recordId;    private String patientId;    private String doctorId;    private LocalDate visitDate;    private String diagnosis;    private String prescription;    private String testResults;    private String notes;    public MedicalRecords(String recordId, String patientId,                          LocalDate visitDate, String doctorId,                          String diagnosis, String prescription,                          String testResults, String notes) {        this.recordId = recordId;        this.patientId = patientId;        this.visitDate = visitDate;        this.doctorId = doctorId;        this.diagnosis = diagnosis;        this.prescription = prescription;        this.testResults = testResults;        this.notes = notes;    }    public String getRecordId() {        return recordId;    }    public void setRecordId(String recordId) {        this.recordId = recordId;    }    public String getPatientId() {        return patientId;    }    public void setPatientId(String patientId) {        this.patientId = patientId;    }    public String getDoctorId() {        return doctorId;    }    public void setDoctorId(String doctorId) {        this.doctorId = doctorId;    }    public LocalDate getVisitDate() {        return visitDate;    }    public void setVisitDate(LocalDate visitDate) {        this.visitDate = visitDate;    }    public String getDiagnosis() {        return diagnosis;    }    public void setDiagnosis(String diagnosis) {        this.diagnosis = diagnosis;    }    public String getPrescription() {        return prescription;    }    public void setPrescription(String prescription) {        this.prescription = prescription;    }    public String getTestResults() {        return testResults;    }    public void setTestResults(String testResults) {        this.testResults = testResults;    }    public String getNotes() {        return notes;    }    public void setNotes(String notes) {        this.notes = notes;    }}